(window.webpackJsonp=window.webpackJsonp||[]).push([[313],{940:function(n,e){n.exports='\x3c!-- \ntitle: 01-Vue入门\nsort: \n--\x3e \n\n> 比React简单,写起来没有React爽\n>\n> 使用`Vue2.16.2`\n\n## HelloWorld\n\n```vue\n<div id="app">\n  <h2>Hello, {{name}}</h2>\n</div>\n\n<script src="https://unpkg.com/vue"><\/script>\n<script>\n  const app = new Vue({\n    // id选择器\n    el: \'#app\',\n    data: {\n      name: \'fzf\'\n    }\n  })\n<\/script>\n```\n\n### 对接API\n\n> 使用b站[API](http://api.bilibili.com/x/web-interface/ranking/region?rid=1)\n\n```vue\n<div id="app">\n  <ul>\n    \x3c!-- for 循环 --\x3e\n    <li v-for="(name,index) in names">\n      {{name}}<br />{{bvs[index]}}<br/>{{coins[index]}}\n      \x3c!-- if判断是否显示 --\x3e\n      <b v-if="coins[index]>=100000">-- Conin Too Much</b>\n    </li>\n  </ul>\n  <h2>Total Number: {{totalCoins}}</h2>\n</div>\n\n<script src="https://unpkg.com/vue"><\/script>\n<script>\n  // 创建Vue实例 \n  const app = new Vue({\n    el: \'#app\',\n    data: {\n      names: [],\n      bvs: [],\n      coins: []\n    },\n    computed:{\n      totalCoins(){\n        return this.coins.reduce((sum,coins)=>sum+coins)\n      },\n      addCoins(){\n        this.coins[0]+=1\n      }\n    },\n    // 创建异步请求\n    created() {\n      fetch(\'data.json\')\n        // 解析JSON数据\n        .then(response => response.json())\n        .then(json => {\n          json.data.map(data => {\n            // PUSH进列表\n            this.names.push(data.title);\n            this.bvs.push(data.bvid);\n            this.coins.push(data.coins);\n          })\n        })\n    }\n  })\n<\/script>\n```\n\n## 指令\n\n```js\n<input v-model="name">\nv-model.lazy="name"\t\t// 惰性更新\nv-model.trim="name"\t\t// 去空格\nv-model.number="name"\t\t// 转换成数字\n```\n\n## 绑定\n\n```js\nv-bind:href="url"\n// 绑定a标签中的href\n:href="url"\n// 绑定class data中要定义isActive\n:class="{active: isActive}\n// 实例 url要定义到data里\n<a :href="url" :class="{active: isActive} >Link</a>\n```\n\n## 事件\n\n```js\nv-on="{click: onClick, keyup: onKeyup}"\n// 绑定点击事件\n@click="onClick"\n// 保护刷新\n@submit.prevent="onSubmit()"\n// 键盘Enter抬起\n@keyup.enter="onKeyup">\n\n// 实例\n<button \n  v-on="{mouseenter: onEnter, mouseout: onOut, click: onClick}"\n  :class="{active: changeColor}"\n>点我</button>\n\nvar app = new Vue({\n  el: \'#app\',\n  data:{\n    changeColor: false,\n  },\n  // 定义事件\n  methods: {\n    onClick: () => {\n      console.log(\'click\')\n      app.changeColor=true\n    },\n    onEnter: () => {\n      console.log(\'mouse in\')\n    },\n    onOut: () => {\n      console.log(\'mouse out\')\n      app.changeColor=false\n    },\n  }\n});\n```\n\n'}}]);